const metrics = $input.first().json;

const currentModels = metrics.models || {};
const rfMetrics = currentModels.random_forest || {};
const trainingInfo = metrics.training_info || {};
const liveMetrics = metrics.live_metrics || {};
const modelStatus = metrics.model_status || {};

return [{
  json: {
    current_state: {
      rf_accuracy: rfMetrics.accuracy || 0,
      rf_f1: rfMetrics.f1_score || 0,
      rf_precision: rfMetrics.precision || 0,
      rf_recall: rfMetrics.recall || 0,
      last_trained: trainingInfo.last_trained || 'never',
      total_samples: trainingInfo.total_samples || 0,
      feature_count: trainingInfo.feature_count || 0
    },
    live_metrics: {
      total_flows: liveMetrics.total_flows || 0,
      anomaly_rate: liveMetrics.anomaly_rate || 0,
      avg_risk_score: liveMetrics.avg_risk_score || 0
    },
    model_status: {
      supervised_loaded: modelStatus.supervised_loaded || false,
      unsupervised_loaded: modelStatus.unsupervised_loaded || false,
      scaler_loaded: modelStatus.scaler_loaded || false
    },
    source: metrics.source || 'unknown',
    timestamp: new Date().toISOString()
  }
}];

const data = $input.first().json;
const state = data.current_state;
const ms = data.model_status;
const live = data.live_metrics;

let subject, body;

if (ms.supervised_loaded && ms.unsupervised_loaded) {
  subject = `NetGuard Training Report - Models Active`;
  body = `# Training Pipeline Status\n\n`;
  body += `**Timestamp:** ${data.timestamp}\n\n`;
  body += `## Current Model Performance\n`;
  body += `- Random Forest Accuracy: **${(state.rf_accuracy * 100).toFixed(1)}%**\n`;
  body += `- F1 Score: **${(state.rf_f1 * 100).toFixed(1)}%**\n`;
  body += `- Precision: **${(state.rf_precision * 100).toFixed(1)}%**\n`;
  body += `- Recall: **${(state.rf_recall * 100).toFixed(1)}%**\n\n`;
  body += `## Model Status\n`;
  body += `- Supervised (RF): ${ms.supervised_loaded ? 'Loaded' : 'NOT loaded'}\n`;
  body += `- Unsupervised (IF): ${ms.unsupervised_loaded ? 'Loaded' : 'NOT loaded'}\n`;
  body += `- Scaler: ${ms.scaler_loaded ? 'Loaded' : 'NOT loaded'}\n\n`;
  body += `## Live Stats\n`;
  body += `- Total Flows Analyzed: **${live.total_flows}**\n`;
  body += `- Anomaly Rate: **${live.anomaly_rate}%**\n`;
  body += `- Avg Risk Score: **${live.avg_risk_score}**\n\n`;
  body += `## Training Info\n`;
  body += `- Last Trained: ${state.last_trained}\n`;
  body += `- Training Samples: ${state.total_samples}\n`;
  body += `- Features: ${state.feature_count}\n\n`;
  body += `---\n`;
  body += `*To retrain: run \`python -m training_pipeline.train\` from the nal/ directory, then restart the backend.*\n`;
} else {
  subject = `NetGuard: Models NOT fully loaded`;
  body = `# Model Status Warning\n\n`;
  body += `**Timestamp:** ${data.timestamp}\n\n`;
  body += `Some models are not loaded:\n`;
  body += `- Supervised (RF): ${ms.supervised_loaded ? 'OK' : 'MISSING'}\n`;
  body += `- Unsupervised (IF): ${ms.unsupervised_loaded ? 'OK' : 'MISSING'}\n`;
  body += `- Scaler: ${ms.scaler_loaded ? 'OK' : 'MISSING'}\n\n`;
  body += `Run the training pipeline to generate model artifacts:\n`;
  body += `\`\`\`\ncd nal\npython -m training_pipeline.train\n\`\`\`\n`;
}

return [{ json: { subject, body, models_loaded: ms.supervised_loaded && ms.unsupervised_loaded, model_status: ms, metrics: state } }];
